import {
  createContext,
  useContext,
  useState,
  useEffect,
  useRef,
  useCallback,
} from 'react';
import { saveSession, getLastSetsForExercise } from '../db';

const WorkoutContext = createContext(null);

const DEFAULT_SET = {
  type: 'N',
  weight: '',
  reps: '',
  time: '',
  rpe: '',
  completed: false,
  previous: null,
};

function makeDefaultSet(prev = null) {
  return { ...DEFAULT_SET, previous: prev };
}

function deepCloneExercises(exercises) {
  return exercises.map(ex => ({
    ...ex,
    supersetGroupId: ex.supersetGroupId ?? null,
    note: ex.note ?? '',
    restTime: ex.restTime ?? null,
    collapsed: false,
    sets: (ex.sets || [{ ...DEFAULT_SET }]).map(s => ({
      ...DEFAULT_SET,
      ...s,
      completed: false,
      previous: null,
    })),
  }));
}

export function WorkoutProvider({ children }) {
  const [session, setSession] = useState(null);
  const [elapsed, setElapsed] = useState(0);
  const [restTimer, setRestTimer] = useState(null);
  const [prBanner, setPrBanner] = useState(null);
  const [prs, setPrs] = useState([]);

  // Refs for timers
  const elapsedIntervalRef = useRef(null);
  const restTimeoutRef = useRef(null);
  const prBannerTimeoutRef = useRef(null);

  // ── Elapsed timer ────────────────────────────────────────────────────────────
  useEffect(() => {
    if (session) {
      elapsedIntervalRef.current = setInterval(() => {
        setElapsed(Math.floor((Date.now() - session.startedAt) / 1000));
      }, 1000);
    } else {
      clearInterval(elapsedIntervalRef.current);
      elapsedIntervalRef.current = null;
      setElapsed(0);
    }
    return () => clearInterval(elapsedIntervalRef.current);
  }, [session?.id]); // only restart when a new session begins

  // ── Rest timer countdown ─────────────────────────────────────────────────────
  useEffect(() => {
    clearTimeout(restTimeoutRef.current);
    if (!restTimer || restTimer.remaining <= 0) {
      if (restTimer?.remaining <= 0) setRestTimer(null);
      return;
    }
    restTimeoutRef.current = setTimeout(() => {
      setRestTimer(prev => {
        if (!prev) return null;
        const next = prev.remaining - 1;
        return next <= 0 ? null : { ...prev, remaining: next };
      });
    }, 1000);
    return () => clearTimeout(restTimeoutRef.current);
  }, [restTimer]);

  // ── Helpers ──────────────────────────────────────────────────────────────────
  function showPrBanner(exerciseName, type, value) {
    clearTimeout(prBannerTimeoutRef.current);
    setPrBanner({ exerciseName, type, value });
    prBannerTimeoutRef.current = setTimeout(() => setPrBanner(null), 3000);
  }

  function clearSessionState() {
    setSession(null);
    setPrs([]);
    setRestTimer(null);
    setPrBanner(null);
    setElapsed(0);
  }

  // ── Public API ───────────────────────────────────────────────────────────────

  const startSession = useCallback(async (routine, settings) => {
    const exercises = deepCloneExercises(routine?.exercises || []);

    // Load previous sets for each exercise
    await Promise.all(
      exercises.map(async ex => {
        const prevSets = await getLastSetsForExercise(ex.name);
        ex.sets = ex.sets.map((s, i) => ({
          ...s,
          previous: prevSets[i]
            ? {
                weight: prevSets[i].weight ?? '',
                reps: prevSets[i].reps ?? '',
                time: prevSets[i].time ?? '',
              }
            : null,
        }));
      })
    );

    const newSession = {
      id: Date.now().toString(),
      routineId: routine?.id ?? null,
      title: routine?.title ?? 'Quick Workout',
      startedAt: Date.now(),
      date: new Date().toISOString(),
      exercises,
    };

    setPrs([]);
    setSession(newSession);
    setElapsed(0);
  }, []);

  const cancelSession = useCallback(() => {
    clearSessionState();
  }, []);

  const finishSession = useCallback(async () => {
    if (!session) return null;
    const finished = {
      ...session,
      finishedAt: Date.now(),
      duration: Math.floor((Date.now() - session.startedAt) / 1000),
    };
    await saveSession(finished);
    clearSessionState();
    return finished;
  }, [session]);

  const setTitle = useCallback(title => {
    setSession(prev => prev ? { ...prev, title } : prev);
  }, []);

  const updateSet = useCallback((exIdx, setIdx, field, value) => {
    setSession(prev => {
      if (!prev) return prev;
      const exercises = prev.exercises.map((ex, ei) => {
        if (ei !== exIdx) return ex;
        return {
          ...ex,
          sets: ex.sets.map((s, si) =>
            si === setIdx ? { ...s, [field]: value } : s
          ),
        };
      });
      return { ...prev, exercises };
    });
  }, []);

  const completeSet = useCallback((exIdx, setIdx, settings) => {
    setSession(prev => {
      if (!prev) return prev;

      const ex = prev.exercises[exIdx];
      const set = ex?.sets[setIdx];
      if (!set) return prev;

      const nowCompleting = !set.completed;

      // PR detection when completing
      if (nowCompleting && set.weight && +set.weight > 0) {
        const exerciseName = ex.name;
        const w = +set.weight;
        const existing = prs.filter(p => p.exerciseName === exerciseName);
        const maxSeen = existing.length > 0 ? Math.max(...existing.map(p => p.weight)) : 0;
        if (w > maxSeen) {
          setPrs(p => [...p, { exerciseName, weight: w, reps: set.reps }]);
          showPrBanner(exerciseName, 'weight', w);
        }
      }

      const exercises = prev.exercises.map((e, ei) => {
        if (ei !== exIdx) return e;
        return {
          ...e,
          sets: e.sets.map((s, si) =>
            si === setIdx ? { ...s, completed: !s.completed } : s
          ),
        };
      });

      const updated = { ...prev, exercises };

      // Start rest timer when completing
      if (nowCompleting) {
        const restSecs = ex.restTime ?? settings?.defaultRest ?? 90;
        setRestTimer({ remaining: restSecs, total: restSecs });
      }

      return updated;
    });
  }, [prs]);

  const cycleSetType = useCallback((exIdx, setIdx) => {
    const ORDER = ['N', 'W', 'D', 'F'];
    setSession(prev => {
      if (!prev) return prev;
      const exercises = prev.exercises.map((ex, ei) => {
        if (ei !== exIdx) return ex;
        return {
          ...ex,
          sets: ex.sets.map((s, si) => {
            if (si !== setIdx) return s;
            const next = ORDER[(ORDER.indexOf(s.type) + 1) % ORDER.length];
            return { ...s, type: next };
          }),
        };
      });
      return { ...prev, exercises };
    });
  }, []);

  const addSet = useCallback(exIdx => {
    setSession(prev => {
      if (!prev) return prev;
      const exercises = prev.exercises.map((ex, ei) => {
        if (ei !== exIdx) return ex;
        const last = ex.sets[ex.sets.length - 1] ?? DEFAULT_SET;
        const newSet = { ...last, completed: false };
        return { ...ex, sets: [...ex.sets, newSet] };
      });
      return { ...prev, exercises };
    });
  }, []);

  const removeSet = useCallback((exIdx, setIdx) => {
    setSession(prev => {
      if (!prev) return prev;
      const ex = prev.exercises[exIdx];
      if (!ex || ex.sets.length <= 1) return prev;
      const exercises = prev.exercises.map((e, ei) => {
        if (ei !== exIdx) return e;
        return { ...e, sets: e.sets.filter((_, si) => si !== setIdx) };
      });
      return { ...prev, exercises };
    });
  }, []);

  const addExercise = useCallback(async (ex, settings) => {
    const prevSets = await getLastSetsForExercise(ex.name);
    const firstSet = makeDefaultSet(
      prevSets[0]
        ? { weight: prevSets[0].weight ?? '', reps: prevSets[0].reps ?? '', time: prevSets[0].time ?? '' }
        : null
    );
    const newEx = {
      id: ex.id ?? Date.now().toString(),
      name: ex.name,
      bodyPart: ex.bodyPart ?? '',
      equipment: ex.equipment ?? '',
      trackingType: ex.trackingType ?? 'reps',
      supersetGroupId: null,
      note: '',
      restTime: null,
      collapsed: false,
      sets: [firstSet],
    };
    setSession(prev => {
      if (!prev) return prev;
      return { ...prev, exercises: [...prev.exercises, newEx] };
    });
  }, []);

  const removeExercise = useCallback(exIdx => {
    setSession(prev => {
      if (!prev) return prev;
      return {
        ...prev,
        exercises: prev.exercises.filter((_, ei) => ei !== exIdx),
      };
    });
  }, []);

  const toggleCollapse = useCallback(exIdx => {
    setSession(prev => {
      if (!prev) return prev;
      const exercises = prev.exercises.map((ex, ei) =>
        ei === exIdx ? { ...ex, collapsed: !ex.collapsed } : ex
      );
      return { ...prev, exercises };
    });
  }, []);

  const updateNote = useCallback((exIdx, note) => {
    setSession(prev => {
      if (!prev) return prev;
      const exercises = prev.exercises.map((ex, ei) =>
        ei === exIdx ? { ...ex, note } : ex
      );
      return { ...prev, exercises };
    });
  }, []);

  const updateRestTime = useCallback((exIdx, secs) => {
    setSession(prev => {
      if (!prev) return prev;
      const exercises = prev.exercises.map((ex, ei) =>
        ei === exIdx ? { ...ex, restTime: secs } : ex
      );
      return { ...prev, exercises };
    });
  }, []);

  const toggleSuperset = useCallback(exIdx => {
    setSession(prev => {
      if (!prev) return prev;
      const exercises = [...prev.exercises];
      const a = exercises[exIdx];
      const b = exercises[exIdx + 1];
      if (!a || !b) return prev;

      if (a.supersetGroupId && a.supersetGroupId === b.supersetGroupId) {
        // Break superset
        exercises[exIdx] = { ...a, supersetGroupId: null };
        exercises[exIdx + 1] = { ...b, supersetGroupId: null };
      } else {
        // Create superset
        const groupId = Date.now().toString();
        exercises[exIdx] = { ...a, supersetGroupId: groupId };
        exercises[exIdx + 1] = { ...b, supersetGroupId: groupId };
      }
      return { ...prev, exercises };
    });
  }, []);

  const skipRestTimer = useCallback(() => {
    setRestTimer(null);
  }, []);

  const adjustRestTimer = useCallback(delta => {
    setRestTimer(prev => {
      if (!prev) return prev;
      const next = Math.max(0, Math.min(600, prev.remaining + delta));
      return { ...prev, remaining: next };
    });
  }, []);

  const autoFillPrev = useCallback((exIdx, setIdx) => {
    setSession(prev => {
      if (!prev) return prev;
      const exercises = prev.exercises.map((ex, ei) => {
        if (ei !== exIdx) return ex;
        return {
          ...ex,
          sets: ex.sets.map((s, si) => {
            if (si !== setIdx || !s.previous) return s;
            return {
              ...s,
              weight: s.previous.weight ?? s.weight,
              reps: s.previous.reps ?? s.reps,
              time: s.previous.time ?? s.time,
            };
          }),
        };
      });
      return { ...prev, exercises };
    });
  }, []);

  const value = {
    session,
    elapsed,
    restTimer,
    prBanner,
    prs,
    startSession,
    cancelSession,
    finishSession,
    setTitle,
    updateSet,
    completeSet,
    cycleSetType,
    addSet,
    removeSet,
    addExercise,
    removeExercise,
    toggleCollapse,
    updateNote,
    updateRestTime,
    toggleSuperset,
    skipRestTimer,
    adjustRestTimer,
    autoFillPrev,
  };

  return (
    <WorkoutContext.Provider value={value}>
      {children}
    </WorkoutContext.Provider>
  );
}

export function useWorkout() {
  const ctx = useContext(WorkoutContext);
  if (!ctx) throw new Error('useWorkout must be used inside WorkoutProvider');
  return ctx;
}
