import { useState, useRef, useEffect } from 'react';
import {
  X,
  ChevronDown,
  MoreVertical,
  Check,
  Plus,
  Minus,
  FileText,
  Clock,
  Link,
  ArrowUp,
  ArrowDown,
  Trash2,
} from 'lucide-react';
import { useWorkout } from '../contexts/WorkoutContext';
import { useApp } from '../contexts/AppContext';
import { fmtTime, fmtVolume, fmtDuration } from '../utils/format';
import { calcVolume, calcSets } from '../utils/stats';
import ExercisesTab from './ExercisesTab';

// ── Set type metadata ─────────────────────────────────────────────────────────
const SET_TYPES = {
  N: { bg: '#374151', color: '#9CA3AF' },
  W: { bg: '#78350F', color: '#F59E0B' },
  D: { bg: '#4C1D95', color: '#A78BFA' },
  F: { bg: '#7F1D1D', color: '#F87171' },
};

const SET_TYPE_OPTIONS = [
  { type: 'W', label: 'Warm Up Set',  color: '#F59E0B', bg: '#78350F' },
  { type: 'N', label: 'Normal Set',   color: '#9CA3AF', bg: '#374151' },
  { type: 'F', label: 'Failure Set',  color: '#F87171', bg: '#7F1D1D' },
  { type: 'D', label: 'Drop Set',     color: '#A78BFA', bg: '#4C1D95' },
];

// ── PR Banner ─────────────────────────────────────────────────────────────────
function PrBanner({ prBanner }) {
  const [visible, setVisible] = useState(false);
  useEffect(() => { setVisible(!!prBanner); }, [prBanner]);
  if (!prBanner) return null;
  return (
    <div style={{
      ...styles.prBanner,
      transform: visible ? 'translateY(0)' : 'translateY(-120%)',
      opacity: visible ? 1 : 0,
      transition: 'transform 0.35s cubic-bezier(0.34,1.56,0.64,1), opacity 0.25s',
    }}>
      🏆 New PR — {prBanner.exerciseName}: {prBanner.value} kg
    </div>
  );
}

// ── Rest Timer Overlay ────────────────────────────────────────────────────────
function RestTimerOverlay({ restTimer, onSkip, onAdjust }) {
  if (!restTimer) return null;
  const { remaining, total } = restTimer;
  const r = 22;
  const circ = 2 * Math.PI * r;
  const dashOffset = circ * (1 - (total > 0 ? remaining / total : 0));

  return (
    <div style={styles.restTimerWrap}>
      <div style={styles.restTimerCard}>
        <button style={styles.restAdjBtn} onClick={() => onAdjust(-15)}>
          <Minus size={14} /><span style={{ fontSize: 11, marginLeft: 2 }}>15s</span>
        </button>
        <div style={styles.restCircleWrap}>
          <svg width={64} height={64} viewBox="0 0 64 64">
            <circle cx={32} cy={32} r={r} fill="none" stroke="#1F2937" strokeWidth={4} />
            <circle cx={32} cy={32} r={r} fill="none" stroke="#3B82F6" strokeWidth={4}
              strokeDasharray={circ} strokeDashoffset={dashOffset} strokeLinecap="round"
              transform="rotate(-90 32 32)" style={{ transition: 'stroke-dashoffset 0.9s linear' }} />
          </svg>
          <span style={styles.restSecs}>{remaining}s</span>
        </div>
        <button style={styles.restAdjBtn} onClick={() => onAdjust(15)}>
          <Plus size={14} /><span style={{ fontSize: 11, marginLeft: 2 }}>15s</span>
        </button>
        <button style={styles.restSkipBtn} onClick={onSkip}><X size={16} /></button>
      </div>
    </div>
  );
}

// ── Set Type Badge ────────────────────────────────────────────────────────────
function SetTypeBadge({ type, setIdx, onClick }) {
  const meta = SET_TYPES[type] ?? SET_TYPES.N;
  const label = (!type || type === 'N') ? String(setIdx + 1) : type;
  return (
    <button
      style={{
        background: meta.bg, color: meta.color,
        border: 'none', borderRadius: 8, fontWeight: 700, fontSize: 13,
        width: 36, height: 36, cursor: 'pointer',
        display: 'flex', alignItems: 'center', justifyContent: 'center', flexShrink: 0,
      }}
      onClick={onClick}
    >
      {label}
    </button>
  );
}

// ── Set Type Sheet ────────────────────────────────────────────────────────────
function SetTypeSheet({ exIdx, setIdx, onClose }) {
  const { updateSet, removeSet } = useWorkout();
  return (
    <div style={{ ...styles.sheetBackdrop, display: 'flex' }} onClick={onClose}>
      <div style={styles.sheetPanel} onClick={e => e.stopPropagation()}>
        <div style={styles.sheetHandle} />
        <div style={{ padding: '16px 20px 8px', fontWeight: 700, fontSize: 17, color: 'var(--text)' }}>
          Select Set Type
        </div>
        {SET_TYPE_OPTIONS.map(({ type, label, color, bg }) => (
          <button key={type}
            onClick={() => { updateSet(exIdx, setIdx, 'type', type); onClose(); }}
            style={{
              display: 'flex', alignItems: 'center', gap: 18, width: '100%',
              padding: '15px 20px', background: 'none', border: 'none',
              borderBottom: '1px solid var(--border)', cursor: 'pointer',
            }}>
            <span style={{
              width: 34, height: 34, borderRadius: 8, background: bg, color,
              fontWeight: 800, fontSize: 15,
              display: 'flex', alignItems: 'center', justifyContent: 'center', flexShrink: 0,
            }}>
              {type === 'N' ? '1' : type}
            </span>
            <span style={{ fontSize: 16, color: 'var(--text)' }}>{label}</span>
          </button>
        ))}
        <button
          onClick={() => { removeSet(exIdx, setIdx); onClose(); }}
          style={{
            display: 'flex', alignItems: 'center', gap: 18, width: '100%',
            padding: '15px 20px', background: 'none', border: 'none', cursor: 'pointer',
          }}>
          <span style={{
            width: 34, height: 34, borderRadius: 8, background: '#450a0a', color: '#f87171',
            fontWeight: 800, fontSize: 15,
            display: 'flex', alignItems: 'center', justifyContent: 'center', flexShrink: 0,
          }}>✕</span>
          <span style={{ fontSize: 16, color: '#f87171' }}>Remove Set</span>
        </button>
      </div>
    </div>
  );
}

// ── Set Row ───────────────────────────────────────────────────────────────────
function SetRow({ set, setIdx, exIdx, isTimeBased, onTypeClick }) {
  const { updateSet, completeSet, autoFillPrev } = useWorkout();
  const { settings } = useApp();

  const prevLabel = set.previous
    ? `${set.previous.weight || '—'}×${set.previous.reps || set.previous.time || '—'}`
    : '—';

  return (
    <div style={{
      ...styles.setRow,
      background: set.completed ? 'rgba(34,197,94,0.07)' : 'transparent',
      transition: 'background 0.2s',
    }}>
      {/* SET number / type badge */}
      <SetTypeBadge
        type={set.type || 'N'}
        setIdx={setIdx}
        onClick={() => onTypeClick(setIdx)}
      />

      {/* PREVIOUS */}
      <button style={styles.prevLabel} onClick={() => autoFillPrev(exIdx, setIdx)}>
        {prevLabel}
      </button>

      {/* KG / LBS */}
      <input
        style={{
          ...styles.setInput,
          borderColor: set.completed ? 'rgba(34,197,94,0.35)' : '#374151',
        }}
        type="number"
        inputMode="decimal"
        placeholder="—"
        value={set.weight ?? ''}
        onChange={e => updateSet(exIdx, setIdx, 'weight', e.target.value)}
      />

      {/* REPS or SEC */}
      <input
        style={{
          ...styles.setInput,
          borderColor: set.completed ? 'rgba(34,197,94,0.35)' : '#374151',
        }}
        type="number"
        inputMode="numeric"
        placeholder="—"
        value={isTimeBased ? (set.time ?? '') : (set.reps ?? '')}
        onChange={e => updateSet(exIdx, setIdx, isTimeBased ? 'time' : 'reps', e.target.value)}
      />

      {/* Checkmark */}
      <button
        style={{
          ...styles.checkBtn,
          background: set.completed ? '#2563EB' : 'transparent',
          border: `2px solid ${set.completed ? '#2563EB' : '#4B5563'}`,
        }}
        onClick={() => completeSet(exIdx, setIdx, settings)}
      >
        {set.completed && <Check size={13} color="#fff" strokeWidth={3} />}
      </button>
    </div>
  );
}

// ── Exercise 3-dot menu ───────────────────────────────────────────────────────
function ExerciseMenu({ exIdx, totalExercises, onClose, onAddNote, onSetRest, onToggleSuperset, onMoveUp, onMoveDown, onRemove }) {
  const ref = useRef(null);
  useEffect(() => {
    function handle(e) {
      if (ref.current && !ref.current.contains(e.target)) onClose();
    }
    document.addEventListener('mousedown', handle);
    document.addEventListener('touchstart', handle);
    return () => {
      document.removeEventListener('mousedown', handle);
      document.removeEventListener('touchstart', handle);
    };
  }, [onClose]);

  return (
    <div ref={ref} style={styles.exMenuDrop}>
      <button style={styles.exMenuItem} onClick={onAddNote}><FileText size={14} />Add Note</button>
      <button style={styles.exMenuItem} onClick={onSetRest}><Clock size={14} />Set Rest Timer</button>
      {exIdx < totalExercises - 1 && (
        <button style={styles.exMenuItem} onClick={onToggleSuperset}>
          <Link size={14} />Toggle Superset with Next
        </button>
      )}
      <div style={styles.menuDivider} />
      <button style={{ ...styles.exMenuItem, opacity: exIdx === 0 ? 0.35 : 1 }} disabled={exIdx === 0} onClick={onMoveUp}>
        <ArrowUp size={14} />Move Up
      </button>
      <button style={{ ...styles.exMenuItem, opacity: exIdx === totalExercises - 1 ? 0.35 : 1 }} disabled={exIdx === totalExercises - 1} onClick={onMoveDown}>
        <ArrowDown size={14} />Move Down
      </button>
      <div style={styles.menuDivider} />
      <button style={{ ...styles.exMenuItem, color: '#F87171' }} onClick={onRemove}>
        <Trash2 size={14} color="#F87171" />Remove Exercise
      </button>
    </div>
  );
}

// ── Note Modal ────────────────────────────────────────────────────────────────
function NoteModal({ currentNote, onSave, onClose }) {
  const [note, setNote] = useState(currentNote ?? '');
  return (
    <div style={styles.modalBackdrop} onClick={onClose}>
      <div style={styles.modalBox} onClick={e => e.stopPropagation()}>
        <div style={styles.modalTitle}>Exercise Note</div>
        <textarea
          style={styles.noteTextarea}
          placeholder="Add a note for this exercise…"
          value={note}
          onChange={e => setNote(e.target.value)}
          autoFocus
          rows={4}
        />
        <div style={styles.modalActions}>
          <button style={styles.modalCancelBtn} onClick={onClose}>Cancel</button>
          <button style={styles.modalSaveBtn} onClick={() => { onSave(note); onClose(); }}>Save</button>
        </div>
      </div>
    </div>
  );
}

// ── Rest Time Modal ───────────────────────────────────────────────────────────
function RestTimeModal({ currentRest, defaultRest, onSave, onClose }) {
  const [secs, setSecs] = useState(currentRest ?? defaultRest ?? 90);
  return (
    <div style={styles.modalBackdrop} onClick={onClose}>
      <div style={styles.modalBox} onClick={e => e.stopPropagation()}>
        <div style={styles.modalTitle}>Rest Timer</div>
        <div style={{ color: '#9CA3AF', fontSize: 13, marginBottom: 14 }}>Override rest time for this exercise.</div>
        <div style={styles.restModalRow}>
          <button style={styles.restModalAdj} onClick={() => setSecs(s => Math.max(0, s - 15))}>−15</button>
          <div style={styles.restModalDisplay}>
            <span style={{ fontSize: 28, fontWeight: 700, color: '#F9FAFB' }}>{secs}</span>
            <span style={{ fontSize: 13, color: '#9CA3AF', marginLeft: 4 }}>sec</span>
          </div>
          <button style={styles.restModalAdj} onClick={() => setSecs(s => Math.min(600, s + 15))}>+15</button>
        </div>
        <input type="range" min={0} max={600} step={5} value={secs}
          onChange={e => setSecs(Number(e.target.value))}
          style={{ width: '100%', marginBottom: 20, accentColor: '#3B82F6' }} />
        <div style={styles.modalActions}>
          <button style={styles.modalCancelBtn} onClick={onClose}>Cancel</button>
          <button style={styles.modalSaveBtn} onClick={() => { onSave(secs); onClose(); }}>Set Timer</button>
        </div>
      </div>
    </div>
  );
}

// ── Exercise Card ─────────────────────────────────────────────────────────────
function ExerciseCard({ ex, exIdx, totalExercises, showMenu, onMenuOpen, onMenuClose, onTypeClick }) {
  const { addSet, removeExercise, updateNote, updateRestTime, toggleSuperset } = useWorkout();
  const [editingNote, setEditingNote] = useState(false);
  const [editingRest, setEditingRest] = useState(false);
  const { settings } = useApp();
  const isTimeBased = ex.trackingType === 'time';

  return (
    <>
      <div style={styles.exCard}>
        {/* Card header */}
        <div style={styles.exCardHeader}>
          <div style={{ flex: 1, minWidth: 0 }}>
            <div style={styles.exCardName}>{ex.name}</div>
          </div>
          <div style={{ position: 'relative' }}>
            <button style={styles.iconBtn} onClick={() => showMenu ? onMenuClose() : onMenuOpen(exIdx)}>
              <MoreVertical size={18} color="#9CA3AF" />
            </button>
            {showMenu && (
              <ExerciseMenu
                exIdx={exIdx}
                totalExercises={totalExercises}
                onClose={onMenuClose}
                onAddNote={() => { onMenuClose(); setEditingNote(true); }}
                onSetRest={() => { onMenuClose(); setEditingRest(true); }}
                onToggleSuperset={() => { onMenuClose(); toggleSuperset(exIdx); }}
                onMoveUp={() => { onMenuClose(); }}
                onMoveDown={() => { onMenuClose(); }}
                onRemove={() => { onMenuClose(); removeExercise(exIdx); }}
              />
            )}
          </div>
        </div>

        {/* Notes row — always visible */}
        <div
          onClick={() => setEditingNote(true)}
          style={{
            fontSize: 14, padding: '0 0 8px', cursor: 'pointer',
            color: ex.note ? 'var(--text2)' : 'var(--text3)',
            fontStyle: ex.note ? 'normal' : 'italic',
          }}
        >
          {ex.note || 'Add notes here...'}
        </div>

        {/* Rest timer row — always visible */}
        <div
          onClick={() => setEditingRest(true)}
          style={{ display: 'flex', alignItems: 'center', gap: 6, fontSize: 13, color: 'var(--accent)', paddingBottom: 12, cursor: 'pointer' }}
        >
          <Clock size={14} />
          Rest Timer: {ex.restTime ? `${ex.restTime}s` : 'OFF'}
        </div>

        {/* Column headers */}
        <div style={styles.setHeaders}>
          <span style={{ width: 36, textAlign: 'center' }}>SET</span>
          <span style={{ flex: 1, textAlign: 'center' }}>PREVIOUS</span>
          <span style={{ width: 64, textAlign: 'center' }}>{settings.units === 'lbs' ? 'LBS' : 'KG'}</span>
          <span style={{ width: 64, textAlign: 'center' }}>{isTimeBased ? 'SEC' : 'REPS'}</span>
          <span style={{ width: 40 }} />
        </div>

        {/* Set rows */}
        {(ex.sets ?? []).map((set, si) => (
          <SetRow
            key={si}
            set={set}
            setIdx={si}
            exIdx={exIdx}
            isTimeBased={isTimeBased}
            onTypeClick={(si) => onTypeClick(exIdx, si)}
          />
        ))}

        {/* Add Set */}
        <button style={styles.addSetBtn} onClick={() => addSet(exIdx)}>
          + Add Set
        </button>
      </div>

      {editingNote && (
        <NoteModal
          currentNote={ex.note}
          onSave={note => updateNote(exIdx, note)}
          onClose={() => setEditingNote(false)}
        />
      )}
      {editingRest && (
        <RestTimeModal
          currentRest={ex.restTime}
          defaultRest={settings.defaultRest}
          onSave={secs => updateRestTime(exIdx, secs)}
          onClose={() => setEditingRest(false)}
        />
      )}
    </>
  );
}

// ── Superset Wrapper ──────────────────────────────────────────────────────────
function SupersetWrap({ children }) {
  return (
    <div style={styles.supersetWrap}>
      <div style={styles.supersetLabel}>SUPERSET</div>
      {children}
    </div>
  );
}

// ── Workout Complete Screen ───────────────────────────────────────────────────
function WorkoutComplete({ session, elapsed, onSave, onBack }) {
  const { setTitle, prs } = useWorkout();
  const { settings } = useApp();
  const [saving, setSaving] = useState(false);

  const volume = calcVolume(session?.exercises ?? []);
  const totalSets = calcSets(session?.exercises ?? []);

  async function handleSave() {
    setSaving(true);
    try { await onSave(); } finally { setSaving(false); }
  }

  return (
    <div style={styles.wcScreen}>
      <div style={styles.wcInner}>
        <div style={styles.wcTrophy}>🏆</div>
        <div style={styles.wcTitle}>Workout Complete!</div>
        <input
          style={styles.wcTitleInput}
          value={session?.title ?? ''}
          onChange={e => setTitle(e.target.value)}
          placeholder="Workout Title"
        />
        <div style={styles.wcStatsGrid}>
          {[
            { label: 'Duration', val: fmtDuration(elapsed) },
            { label: 'Volume',   val: fmtVolume(volume, settings.units) },
            { label: 'Sets',     val: totalSets },
          ].map(({ label, val }) => (
            <div key={label} style={styles.wcStatCell}>
              <div style={styles.wcStatVal}>{val}</div>
              <div style={styles.wcStatLabel}>{label}</div>
            </div>
          ))}
        </div>

        {prs.length > 0 && (
          <div style={styles.wcSection}>
            <div style={styles.wcSectionTitle}>Personal Records</div>
            {prs.map((pr, i) => (
              <div key={i} style={styles.wcPrRow}>
                <span style={styles.wcPrBadge}>PR</span>
                <span style={styles.wcPrName}>{pr.exerciseName}</span>
                <span style={styles.wcPrVal}>{pr.weight} {settings.units} × {pr.reps}</span>
              </div>
            ))}
          </div>
        )}

        <div style={styles.wcSection}>
          <div style={styles.wcSectionTitle}>Exercises</div>
          {(session?.exercises ?? []).map((ex, i) => {
            const done = ex.sets?.filter(s => s.completed).length ?? 0;
            return (
              <div key={i} style={styles.wcExRow}>
                <span style={styles.wcExName}>{ex.name}</span>
                <span style={styles.wcExSets}>{done}/{ex.sets?.length ?? 0} sets</span>
              </div>
            );
          })}
        </div>

        <button style={{ ...styles.saveWorkoutBtn, opacity: saving ? 0.6 : 1 }} disabled={saving} onClick={handleSave}>
          {saving ? 'Saving…' : 'Save Workout'}
        </button>
        <button style={styles.wcBackBtn} onClick={onBack}>Back to Workout</button>
      </div>
    </div>
  );
}

// ── LiveWorkout (main export) ─────────────────────────────────────────────────
export default function LiveWorkout({ onFinished }) {
  const {
    session, elapsed, restTimer, prBanner,
    cancelSession, finishSession, setTitle, addExercise,
    skipRestTimer, adjustRestTimer,
  } = useWorkout();
  const { settings } = useApp();

  const [showMenu, setShowMenu] = useState(null);
  const [showComplete, setShowComplete] = useState(false);
  const [showPicker, setShowPicker] = useState(false);
  const [setTypePicker, setSetTypePicker] = useState(null); // {exIdx, setIdx}
  const bodyRef = useRef(null);

  if (!session) return null;

  const exercises = session.exercises ?? [];
  const totalSets = exercises.reduce((a, ex) => a + (ex.sets?.length ?? 0), 0);
  const completedSets = exercises.reduce((a, ex) => a + (ex.sets?.filter(s => s.completed).length ?? 0), 0);
  const progressPct = totalSets > 0 ? (completedSets / totalSets) * 100 : 0;
  const totalVolume = calcVolume(exercises);

  function buildGroups(exs) {
    const groups = [];
    let i = 0;
    while (i < exs.length) {
      const ex = exs[i];
      const gid = ex.supersetGroupId;
      if (gid && i + 1 < exs.length && exs[i + 1].supersetGroupId === gid) {
        const members = [{ ex, idx: i }];
        let j = i + 1;
        while (j < exs.length && exs[j].supersetGroupId === gid) {
          members.push({ ex: exs[j], idx: j });
          j++;
        }
        groups.push({ type: 'superset', members });
        i = j;
      } else {
        groups.push({ type: 'single', ex, idx: i });
        i++;
      }
    }
    return groups;
  }

  const groups = buildGroups(exercises);

  async function handlePick(ex) {
    setShowPicker(false);
    await addExercise(ex, settings);
    setTimeout(() => {
      bodyRef.current?.scrollTo({ top: bodyRef.current.scrollHeight, behavior: 'smooth' });
    }, 100);
  }

  async function handleFinishConfirm() {
    try {
      await finishSession();
      onFinished?.();
    } catch {
      alert('Could not save workout. Please try again.');
    }
  }

  if (showComplete) {
    return (
      <div style={styles.overlay}>
        <WorkoutComplete
          session={session}
          elapsed={elapsed}
          onSave={handleFinishConfirm}
          onBack={() => setShowComplete(false)}
        />
      </div>
    );
  }

  return (
    <div style={styles.overlay}>
      <PrBanner prBanner={prBanner} />

      {/* Header */}
      <div style={styles.liveHeader}>
        <button style={styles.iconBtn} onClick={() => {}}>
          <ChevronDown size={22} color="var(--text)" />
        </button>
        <input
          style={styles.liveTitleInput}
          value={session.title}
          onChange={e => setTitle(e.target.value)}
          placeholder="Log Workout"
        />
        <button style={styles.iconBtn}>
          <Clock size={20} color="var(--text2)" />
        </button>
        <button style={styles.finishBtn} onClick={() => setShowComplete(true)}>
          Finish
        </button>
      </div>

      {/* Stats bar */}
      <div style={styles.statsBar}>
        <div style={styles.statCell}>
          <span style={styles.statLabel}>Duration</span>
          <span style={{ ...styles.statVal, color: 'var(--accent)' }}>{fmtTime(elapsed)}</span>
        </div>
        <div style={styles.statDivider} />
        <div style={styles.statCell}>
          <span style={styles.statLabel}>Volume</span>
          <span style={styles.statVal}>{fmtVolume(totalVolume, settings.units)}</span>
        </div>
        <div style={styles.statDivider} />
        <div style={styles.statCell}>
          <span style={styles.statLabel}>Sets</span>
          <span style={styles.statVal}>{completedSets}</span>
        </div>
      </div>

      {/* Progress bar */}
      <div style={styles.progressTrack}>
        <div style={{ ...styles.progressFill, width: `${progressPct}%`, transition: 'width 0.4s ease' }} />
      </div>

      {/* Scrollable body */}
      <div ref={bodyRef} style={styles.liveBody}>
        {groups.map((group, gi) => {
          if (group.type === 'superset') {
            return (
              <SupersetWrap key={`ss-${gi}`}>
                {group.members.map(({ ex, idx }) => (
                  <ExerciseCard key={idx} ex={ex} exIdx={idx} totalExercises={exercises.length}
                    showMenu={showMenu === idx}
                    onMenuOpen={i => setShowMenu(i)}
                    onMenuClose={() => setShowMenu(null)}
                    onTypeClick={(ei, si) => setSetTypePicker({ exIdx: ei, setIdx: si })}
                  />
                ))}
              </SupersetWrap>
            );
          }
          return (
            <ExerciseCard key={group.idx} ex={group.ex} exIdx={group.idx} totalExercises={exercises.length}
              showMenu={showMenu === group.idx}
              onMenuOpen={i => setShowMenu(i)}
              onMenuClose={() => setShowMenu(null)}
              onTypeClick={(ei, si) => setSetTypePicker({ exIdx: ei, setIdx: si })}
            />
          );
        })}

        {exercises.length === 0 && (
          <div style={{ fontSize: 14, color: '#6B7280', textAlign: 'center', padding: '48px 0' }}>
            No exercises yet. Tap "+ Add Exercise" below.
          </div>
        )}

        {/* Add Exercise */}
        <button style={styles.addExBtn} onClick={() => setShowPicker(true)}>
          <Plus size={16} style={{ marginRight: 8 }} />
          Add Exercise
        </button>

        {/* Settings + Discard */}
        <div style={{ display: 'flex', gap: 10 }}>
          <button style={styles.settingsBtn}>Settings</button>
          <button style={styles.discardBtn} onClick={() => {
            if (window.confirm('Discard this workout? All progress will be lost.')) cancelSession();
          }}>
            Discard Workout
          </button>
        </div>

        <div style={{ height: restTimer ? 100 : 32 }} />
      </div>

      <RestTimerOverlay restTimer={restTimer} onSkip={skipRestTimer} onAdjust={adjustRestTimer} />

      {/* Set type picker sheet */}
      {setTypePicker && (
        <SetTypeSheet
          exIdx={setTypePicker.exIdx}
          setIdx={setTypePicker.setIdx}
          onClose={() => setSetTypePicker(null)}
        />
      )}

      {/* Exercise picker sheet — always mounted after first open to avoid reload lag */}
      <div
        style={{ ...styles.sheetBackdrop, display: showPicker ? 'flex' : 'none' }}
        onClick={() => setShowPicker(false)}
      >
        <div style={styles.sheetPanel} onClick={e => e.stopPropagation()}>
          <div style={styles.sheetHandle} />
          <div style={styles.sheetHeaderRow}>
            <span style={styles.sheetTitleText}>Add Exercise</span>
            <button style={styles.iconBtn} onClick={() => setShowPicker(false)}>
              <X size={20} color="#9CA3AF" />
            </button>
          </div>
          <div style={styles.sheetBody}>
            <ExercisesTab pickerMode onPick={handlePick} />
          </div>
        </div>
      </div>
    </div>
  );
}

